struct Card { int a, c, id; };

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<Card> cards(n);
    for (int i = 0; i < n; ++i) {
        cin >> cards[i].a >> cards[i].c;
        cards[i].id = i + 1;
    }
    sort(cards.begin(), cards.end(), [](const Card &x, const Card &y) {
        if (x.a != y.a) return x.a > y.a;
        return x.c < y.c;
    });
    const int INF = 1e9 + 7;
    int min_stronger_cost = INF;
    vector<int> alive;
    for (int i = 0; i < n; ) {
        int j = i;
        while (j < n && cards[j].a == cards[i].a) ++j;
        for (int k = i; k < j; ++k) {
            if (min_stronger_cost >= cards[k].c) alive.push_back(cards[k].id);
        }
        for (int k = i; k < j; ++k) min_stronger_cost = min(min_stronger_cost, cards[k].c);
        i = j;
    }
    sort(alive.begin(), alive.end());
    cout << alive.size() << '\n';
    for (int i = 0; i < (int)alive.size(); ++i) {
        if (i) cout << ' ';
        cout << alive[i];
    }
    cout << '\n';
    return 0;
}

